-- Migration v129: Glossar — term_en Feld + 5 neue Kategorien + 120 Excel-Datensätze

-- 1. Spalte term_en hinzufügen
ALTER TABLE dk_glossar          ADD COLUMN IF NOT EXISTS term_en TEXT NOT NULL DEFAULT '';
ALTER TABLE dk_glossar_defaults ADD COLUMN IF NOT EXISTS term_en TEXT NOT NULL DEFAULT '';

-- 2. Englische Übersetzungen für bestehende 25 Defaults (kuerzel-Kategorie)
UPDATE dk_glossar_defaults SET term_en = 'Pick-up'                            WHERE kuerzel = 'PU';
UPDATE dk_glossar_defaults SET term_en = 'Direct Pick-up'                     WHERE kuerzel = 'DPU'  AND name NOT LIKE '%(Eröffnungs%';
UPDATE dk_glossar_defaults SET term_en = 'Continuous Action'                  WHERE kuerzel = 'CA';
UPDATE dk_glossar_defaults SET term_en = 'Indirect Pick-up'                   WHERE kuerzel = 'IPU'  AND name NOT LIKE '%(Eröffnungs%';
UPDATE dk_glossar_defaults SET term_en = 'Direct Pick-up (Opening Marker)'    WHERE kuerzel = 'DPU.';
UPDATE dk_glossar_defaults SET term_en = 'Indirect Pick-up (Opening Marker)'  WHERE kuerzel = 'IPU.';
UPDATE dk_glossar_defaults SET term_en = 'Parking a storyline / Hold'         WHERE kuerzel = 'Parken';
UPDATE dk_glossar_defaults SET term_en = 'Penultimate (pre-cliffhanger scene)' WHERE kuerzel = 'PEN';
UPDATE dk_glossar_defaults SET term_en = 'Cliffhanger'                        WHERE kuerzel = 'CLIFF';
UPDATE dk_glossar_defaults SET term_en = 'Solo scene'                         WHERE kuerzel = 'SOLO';
UPDATE dk_glossar_defaults SET term_en = 'Crosscut / Intercut'                WHERE kuerzel = 'WS';
UPDATE dk_glossar_defaults SET term_en = 'Split Screen'                       WHERE kuerzel = 'Split-Screen';
UPDATE dk_glossar_defaults SET term_en = 'One-Way Phone Call'                 WHERE kuerzel = '1W';
UPDATE dk_glossar_defaults SET term_en = 'Two-Way Phone Call'                 WHERE kuerzel = '2W';
UPDATE dk_glossar_defaults SET term_en = 'Voice Over (V.O.)'                  WHERE kuerzel = 'VO';
UPDATE dk_glossar_defaults SET term_en = 'Off-screen (O.S.)'                  WHERE kuerzel = 'OFF';
UPDATE dk_glossar_defaults SET term_en = 'Sound Only'                         WHERE kuerzel = 'NT';
UPDATE dk_glossar_defaults SET term_en = 'Insert / Pre-recorded footage'      WHERE kuerzel = 'Einspieler';
UPDATE dk_glossar_defaults SET term_en = 'At production''s discretion'        WHERE kuerzel = 'NMDP' AND name NOT LIKE '%Komparsen%';
UPDATE dk_glossar_defaults SET term_en = 'At discretion (extras)'             WHERE kuerzel = 'NMDP-Komparsen';
UPDATE dk_glossar_defaults SET term_en = 'No lines (N.L.)'                    WHERE kuerzel = 'o.T.';
UPDATE dk_glossar_defaults SET term_en = 'Sexual encounter begins'             WHERE kuerzel = 'SBSA';
UPDATE dk_glossar_defaults SET term_en = 'Shadow script'                      WHERE kuerzel = 'Schattenbuch';
UPDATE dk_glossar_defaults SET term_en = 'Casting scene'                      WHERE kuerzel = 'Casting-Szene';
UPDATE dk_glossar_defaults SET term_en = 'Spin-off'                           WHERE kuerzel = 'Spin-Off';

-- 3. Bestehende dk_glossar-Einträge (Produktions-Kopien) per Kürzel+Name rückwärts befüllen
UPDATE dk_glossar g
SET term_en = d.term_en
FROM dk_glossar_defaults d
WHERE g.kuerzel = d.kuerzel AND g.name = d.name AND g.term_en = '' AND d.term_en <> '';

